/*! msal-browser-shim v1.0 — PKCE + Authorization Code Flow
 *  Compatível com GitHub Pages + Microsoft Entra ID
 *  Implementa: PublicClientApplication com loginPopup, acquireTokenSilent, 
 *  getAllAccounts, handleRedirectPromise
 */
(function(global){
'use strict';

// Helpers PKCE
function b64url(buf){
  return btoa(String.fromCharCode.apply(null,new Uint8Array(buf)))
    .replace(/\+/g,'-').replace(/\//g,'_').replace(/=+$/,'');
}
async function pkceChallenge(){
  var verifier=b64url(crypto.getRandomValues(new Uint8Array(32)));
  var enc=new TextEncoder();
  var digest=await crypto.subtle.digest('SHA-256',enc.encode(verifier));
  return {verifier:verifier, challenge:b64url(digest)};
}
function genNonce(){return b64url(crypto.getRandomValues(new Uint8Array(16)));}
function parseJwt(t){try{return JSON.parse(atob(t.split('.')[1].replace(/-/g,'+').replace(/_/g,'/')));}catch(e){return {};}}

function PublicClientApplication(config){
  this._cfg=config;
  this._store=config.cache&&config.cache.cacheLocation==='localStorage'?localStorage:sessionStorage;
  this._key='msal_shim_'+config.auth.clientId;
}

PublicClientApplication.prototype._save=function(data){
  this._store.setItem(this._key,JSON.stringify(data));
};
PublicClientApplication.prototype._load=function(){
  try{return JSON.parse(this._store.getItem(this._key)||'null');}catch(e){return null;}
};
PublicClientApplication.prototype.getAllAccounts=function(){
  var d=this._load();
  if(d&&d.account)return[d.account];
  return[];
};
PublicClientApplication.prototype.handleRedirectPromise=function(){
  return Promise.resolve(null);
};

PublicClientApplication.prototype.acquireTokenSilent=function(req){
  var self=this;
  return new Promise(async function(resolve,reject){
    var d=self._load();
    if(!d||!d.refresh_token){reject(new Error('no_token'));return;}
    // Verificar se access token ainda é válido (5min de margem)
    if(d.access_token&&d.expires_at&&Date.now()<d.expires_at-300000){
      resolve({accessToken:d.access_token,account:d.account});
      return;
    }
    // Renovar via refresh token
    try{
      var body=new URLSearchParams({
        client_id:self._cfg.auth.clientId,
        grant_type:'refresh_token',
        refresh_token:d.refresh_token,
        scope:(req.scopes||d.scopes||[]).join(' ')+' offline_access'
      });
      var r=await fetch('https://login.microsoftonline.com/'+
        self._cfg.auth.authority.split('/').pop()+'/oauth2/v2.0/token',
        {method:'POST',body:body,headers:{'Content-Type':'application/x-www-form-urlencoded'}});
      if(!r.ok){reject(new Error('refresh_failed'));return;}
      var t=await r.json();
      if(t.error){reject(new Error(t.error));return;}
      d.access_token=t.access_token;
      d.expires_at=Date.now()+t.expires_in*1000;
      if(t.refresh_token)d.refresh_token=t.refresh_token;
      self._save(d);
      resolve({accessToken:t.access_token,account:d.account});
    }catch(e){reject(e);}
  });
};

PublicClientApplication.prototype.loginPopup=function(req){
  var self=this;
  return new Promise(async function(resolve,reject){
    try{
      var pkce=await pkceChallenge();
      var nonce=genNonce();
      var state=genNonce();
      var scopes=((req&&req.scopes)||[]).concat(['offline_access']).join(' ');
      var tenantId=self._cfg.auth.authority.split('/').pop();
      var redirectUri=self._cfg.auth.redirectUri||location.origin+location.pathname;
      var popupUri='https://login.microsoftonline.com/'+tenantId+'/oauth2/v2.0/authorize?'+
        'client_id='+encodeURIComponent(self._cfg.auth.clientId)+
        '&response_type=code'+
        '&redirect_uri='+encodeURIComponent(redirectUri)+
        '&scope='+encodeURIComponent(scopes)+
        '&state='+state+
        '&nonce='+nonce+
        '&code_challenge='+pkce.challenge+
        '&code_challenge_method=S256'+
        '&prompt=select_account';

      // Abrir popup
      var w=800,h=600,left=(screen.width-w)/2,top=(screen.height-h)/2;
      var popup=window.open(popupUri,'msalPopup',
        'width='+w+',height='+h+',left='+left+',top='+top+',toolbar=0,location=0,status=0,menubar=0');
      if(!popup){reject(new Error('Popup bloqueado. Permita popups para este site.'));return;}

      // Monitorar popup
      var timer=setInterval(async function(){
        try{
          if(!popup||popup.closed){
            clearInterval(timer);
            reject(new Error('Login cancelado pelo usuario.'));
            return;
          }
          var url='';
          try{url=popup.location.href;}catch(e){return;}
          if(!url||url==='about:blank')return;
          if(url.indexOf(redirectUri)===0||url.indexOf(location.origin+location.pathname)===0){
            popup.close();
            clearInterval(timer);
            var params=new URL(url).searchParams;
            var code=params.get('code');
            var retState=params.get('state');
            if(!code){reject(new Error('Sem codigo de autorizacao. Tente novamente.'));return;}
            if(retState!==state){reject(new Error('State inválido.'));return;}
            // Trocar code por tokens
            var body=new URLSearchParams({
              client_id:self._cfg.auth.clientId,
              grant_type:'authorization_code',
              code:code,
              redirect_uri:redirectUri,
              code_verifier:pkce.verifier,
              scope:scopes
            });
            var r=await fetch('https://login.microsoftonline.com/'+tenantId+'/oauth2/v2.0/token',
              {method:'POST',body:body,headers:{'Content-Type':'application/x-www-form-urlencoded'}});
            var t=await r.json();
            if(t.error){reject(new Error(t.error_description||t.error));return;}
            var claims=parseJwt(t.id_token||t.access_token);
            var account={homeAccountId:claims.oid||claims.sub,username:claims.upn||claims.preferred_username||claims.email||'usuario',name:claims.name||'Usuário'};
            var data={access_token:t.access_token,refresh_token:t.refresh_token||null,expires_at:Date.now()+t.expires_in*1000,account:account,scopes:scopes.split(' ')};
            self._save(data);
            resolve({accessToken:t.access_token,account:account,idToken:t.id_token});
          }
        }catch(err){}
      },300);
    }catch(e){reject(e);}
  });
};

// Expor como global
var msalModule={PublicClientApplication:PublicClientApplication,BrowserAuthError:{createPopupWindowError:function(){return new Error('popup_error');}}};
if(typeof module!=='undefined'&&module.exports){module.exports=msalModule;}
else{global.msal=msalModule;}

})(typeof globalThis!=='undefined'?globalThis:typeof window!=='undefined'?window:this);
